  const notes = addGlassCard(frame, { x: 96, y: 620, width: 1728, height: 276, fill: palette.card, glow: palette.orange });
  await addBulletColumn(notes, spec.content, { x: 36, y: 36, width: 700, fontSize: 24, lineHeight: 32 });
